# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import os
from selenium import webdriver
from PIL import Image
import boto3

s3 = boto3.client('s3')
driver_path = '/usr/bin/headless-chromium'  # or PhantomJS path

def generate_screenshot(url):
    options = webdriver.ChromeOptions()
    options.add_argument('headless')
    driver = webdriver.Chrome(driver_path, chrome_options=options)

    driver.get(url)
    driver.save_screenshot('screenshot.png')

    element = driver.find_element_by_xpath('//body')
    location = element.location
    size = element.size

    left = location['x']
    top = location['y']
    width = size['width']
    height = size['height']

    driver.get_screenshot_as_png()

    img = Image.open('screenshot.png')
    cropped_image = img.crop((left, top, left + width, top + height))

    bucket_name = 'your-bucket-name'
    file_name = 'thumbnail-{}'.format(hash(url))
    s3.upload_file('thumbnail.png', bucket_name, file_name)

def main():
    url = input("Enter URL: ")
    generate_screenshot(url)
    print("Thumbnail uploaded to S3")

if __name__ == "__main__":
    main()